import React from 'react';

function Experience({ data }) {
  if (!data) return null;

  return (
    <section id="experience" className="py-16 md:py-24 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-12">
          Experience
        </p>

        <div className="space-y-12">
          {data.map((exp) => (
            <div key={exp.id} className="border-b border-gray-200 pb-12 last:border-0">
              <h3 className="text-2xl font-black text-gray-900 mb-2">
                {exp.position}
              </h3>
              <p className="text-base text-gray-600 mb-4">
                {exp.company} • {exp.period}
              </p>
              <ul className="space-y-3">
                {exp.description.map((item, idx) => (
                  <li key={idx} className="text-base text-gray-600 leading-relaxed flex gap-3">
                    <span className="text-gray-300 mt-1">▸</span>
                    <span>{item}</span>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Experience;
